import{_ as a,o as t,c as r,a7 as s}from"./chunks/framework.C5fSpjcB.js";const u=JSON.parse('{"title":"Designated Realms","description":"","frontmatter":{},"headers":[],"relativePath":"en/realms/index.md","filePath":"en/realms/index.md","lastUpdated":1775394001000}'),l={name:"en/realms/index.md"};function i(n,e,o,d,m,h){return t(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="designated-realms" tabindex="-1">Designated Realms <a class="header-anchor" href="#designated-realms" aria-label="Permalink to &quot;Designated Realms&quot;">​</a></h1><p>Morimens features four <strong>Designated Realms</strong> (指定领域), each representing a distinct school of eldritch power. Every Awakener and most cards belong to one realm, and building your team around a shared realm activates powerful synergies.</p><h2 id="realm-overview" tabindex="-1">Realm Overview <a class="header-anchor" href="#realm-overview" aria-label="Permalink to &quot;Realm Overview&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Realm</th><th>Theme</th><th>Core Mechanic</th><th>Playstyle</th></tr></thead><tbody><tr><td><span class="realm-badge realm-chaos">Chaos</span> (混沌)</td><td>Primordial disorder</td><td>Mix realms freely; accelerate Silver Key generation</td><td>Flexible hybrid; Key Order focused</td></tr><tr><td><span class="realm-badge realm-aequor">Aequor</span> (深海)</td><td>Abyssal deep sea</td><td>Summon and empower Tentacle entities</td><td>Summon-based sustained damage</td></tr><tr><td><span class="realm-badge realm-caro">Caro</span> (血肉)</td><td>Flesh and mutation</td><td>Create and consume Embryo cards</td><td>Burst combos; hand management</td></tr><tr><td><span class="realm-badge realm-ultra">Ultra</span> (超维)</td><td>Higher dimensions</td><td>Gain extra turns from playing cards</td><td>Speed chains; low-cost card spam</td></tr></tbody></table><h2 id="realm-synergy" tabindex="-1">Realm Synergy <a class="header-anchor" href="#realm-synergy" aria-label="Permalink to &quot;Realm Synergy&quot;">​</a></h2><p>When your team is composed of Awakeners from the same realm, realm-specific synergy bonuses activate. These bonuses enhance the core mechanic of that realm.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p><span class="realm-badge realm-chaos">Chaos</span> Awakeners can be slotted into any realm team without breaking synergy, making them ideal flexible picks.</p></div><h2 id="choosing-a-realm" tabindex="-1">Choosing a Realm <a class="header-anchor" href="#choosing-a-realm" aria-label="Permalink to &quot;Choosing a Realm&quot;">​</a></h2><ul><li><strong>New players</strong> -- Start with whichever realm your best Awakeners belong to.</li><li><strong>Roster building</strong> -- Over time, aim to build at least one functional team for each realm.</li><li><strong>Content adaptation</strong> -- Some stages and bosses are easier with specific realm strategies.</li></ul><h2 id="realm-pages" tabindex="-1">Realm Pages <a class="header-anchor" href="#realm-pages" aria-label="Permalink to &quot;Realm Pages&quot;">​</a></h2><ul><li><a href="./chaos.html">Chaos</a> -- Primordial flexibility and Silver Key mastery</li><li><a href="./aequor.html">Aequor</a> -- Deep-sea Tentacle summoning</li><li><a href="./caro.html">Caro</a> -- Flesh Embryo creation and consumption</li><li><a href="./ultra.html">Ultra</a> -- Dimensional extra turn chains</li></ul><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="./../awakeners/team-building.html">Team Building</a></li><li><a href="./../cards/deckbuilding.html">Deckbuilding Guide</a></li><li><a href="./../awakeners/list.html">Awakener List</a></li></ul>',13)])])}const g=a(l,[["render",i]]);export{u as __pageData,g as default};
